import xml.etree.ElementTree as ET
from io import StringIO
from flask import request, jsonify

def validate_xml():
    file = request.files['file']
    try:
        data = file.stream.read()
        root = ET.parse(StringIO(data.decode())).getroot()
        for child in root:
            if len(child) > 0 or (child.text and child.text.strip()):
                return "Valid XML Document"
        return "Invalid XML Document. Empty elements or attributes are not allowed."
    except Exception as e:
        return str(e)

@app.route('/validate_xml', methods=['POST'])
def validate():
    result = validate_xml()
    return jsonify({'result': result})